    // Build adjacency list
    graph := make(map[int64][][3]int64)
    for _, edge := range edges {
        u, v, s, e := edge[0], edge[1], edge[2], edge[3]
        graph[u] = append(graph[u], [3]int64{v, s, e})
    }

    // Priority queue: (time, node)
    pq := &PriorityQueue{}
    heap.Init(pq)
    heap.Push(pq, Item{0, 0})

    // Visited map to keep track of the earliest time we reach each node
    visited := make(map[int64]int64)

    for pq.Len() > 0 {
        item := heap.Pop(pq).(*Item)
        time := item.time
        node := item.node

        // If we've already reached this node with an earlier time, skip
        if prevTime, ok := visited[node]; ok && prevTime <= time {
            continue
        }

        // Mark the earliest time we reach this node
        visited[node] = time

        // If we've reached the destination, return the time
        if node == n-1 {
            return time
        }

        // Explore neighbors
        for _, edge := range graph[node] {
            neighbor, start, end := edge[0], edge[1], edge[2]

            // Check if we can take this edge at the current time
            if start <= time && time <= end {
                // We can take the edge, move to the neighbor at time + 1
                newTime := time + 1
                if _, ok := visited[neighbor]; !ok || newTime < visited[neighbor] {
                    heap.Push(pq, Item{newTime, neighbor})
                }
            } else {
                // If the edge is not available at current time, we can wait until it becomes available
